/*
 * seed-demo-documents.js
 *
 * Attaches the four fabricated combined arc-flash report + one-line PDFs (2022 & 2026 for Cedar
 * Hollow Pump Station and Northgate Medical Center) as downloadable site-level Documents on the
 * demo account, so a demo can open/point to/download them. Pairs with
 * seed-cedar-northgate-drift-demo.js (which creates the sites + arc-flash studies).
 *
 * The PDF bytes are embedded base64 (kept out of a separate binary asset so the script is
 * self-contained and copied into the image with no Dockerfile/.dockerignore assumptions).
 * Writes to LOCAL storage only (the demo's configured backend); guards and SKIPS if the account
 * or global config uses S3, so it never creates a Document the server would try to serve from a
 * bucket that has no such object. Idempotent: replaces its own docs (by site+filename) on re-run,
 * deleting the prior on-disk file first. Not part of seed-demo.js — re-run after a full reseed.
 *
 * Run inside the server container:
 *   docker compose exec -T server node scripts/seed-demo-documents.js
 */

require('dotenv').config({ path: require('path').join(__dirname, '..', '.env') });
const fs = require('fs');
const path = require('path');
const { PrismaClient } = require('@prisma/client');
const prisma = new PrismaClient();

const DEMO_ACCOUNT_ID = '11111111-1111-4111-8111-111111111111';
const STORAGE_LOCAL = path.resolve(process.env.STORAGE_LOCAL_PATH || '/app/uploads');

// mirrors lib/storage.ts buildStorageKey(accountId, filename, assetId=null)
function buildKey(accountId, filename) {
  const ts = Date.now();
  const safe = filename.replace(/[^a-zA-Z0-9.\-_]/g, '_');
  return accountId + '/misc/' + ts + '_' + safe;
}

const DOCS = [{"site": "Cedar Hollow Pump Station", "filename": "Cedar Hollow Pump Station - Arc-Flash Report and One-Line (2022).pdf", "uploadedAt": "2022-03-15T14:02:00Z", "b64": "", "bytes": 24554}, {"site": "Cedar Hollow Pump Station", "filename": "Cedar Hollow Pump Station - Arc-Flash Report and One-Line (2026).pdf", "uploadedAt": "2026-02-11T09:41:00Z", "b64": "", "bytes": 27658}, {"site": "Northgate Medical Center", "filename": "Northgate Medical Center - Arc-Flash Report and One-Line (2022).pdf", "uploadedAt": "2022-09-22T16:20:00Z", "b64": "", "bytes": 24201}, {"site": "Northgate Medical Center", "filename": "Northgate Medical Center - Arc-Flash Report and One-Line (2026).pdf", "uploadedAt": "2026-03-31T11:08:00Z", "b64": "", "bytes": 27802}];

async function main() {
  const dest = (process.env.STORAGE_DEST || 'local').toLowerCase();
  const acct = await prisma.account.findUnique({ where: { id: DEMO_ACCOUNT_ID }, select: { id: true, companyName: true, storageProvider: true } });
  if (!acct) { console.log('SKIP: demo account not found (' + DEMO_ACCOUNT_ID + ')'); return; }
  if (dest !== 'local' || acct.storageProvider === 's3') {
    console.log('SKIP: storage is not local (STORAGE_DEST=' + dest + ', account.storageProvider=' + acct.storageProvider + '). This seed writes local files; adapt to lib/storage.uploadFile for S3.');
    return;
  }
  const uploader = await prisma.user.findFirst({ where: { accountId: DEMO_ACCOUNT_ID }, orderBy: { createdAt: 'asc' }, select: { id: true, email: true } });
  if (!uploader) { console.log('SKIP: no user in demo account to set uploadedBy'); return; }
  console.log('Seeding demo documents into account: ' + (acct.companyName || acct.id) + ' (uploader ' + uploader.email + ')');

  for (const d of DOCS) {
    const site = await prisma.site.findFirst({ where: { accountId: DEMO_ACCOUNT_ID, name: d.site }, select: { id: true } });
    if (!site) { console.log('SKIP (site not found): ' + d.site + ' / ' + d.filename); continue; }
    // idempotent: drop prior copies of this exact doc on this site (+ their on-disk files)
    const prior = await prisma.document.findMany({ where: { accountId: DEMO_ACCOUNT_ID, siteId: site.id, filename: d.filename }, select: { id: true, filePath: true } });
    for (const p of prior) {
      try { if (p.filePath && p.filePath !== '__external__') fs.unlinkSync(path.join(STORAGE_LOCAL, p.filePath)); } catch (e) { /* already gone */ }
    }
    if (prior.length) await prisma.document.deleteMany({ where: { id: { in: prior.map((p) => p.id) } } });

    const buf = Buffer.from(d.b64, 'base64');
    const key = buildKey(DEMO_ACCOUNT_ID, d.filename);
    const abs = path.join(STORAGE_LOCAL, key);
    fs.mkdirSync(path.dirname(abs), { recursive: true });
    fs.writeFileSync(abs, buf);

    await prisma.document.create({ data: {
      accountId: DEMO_ACCOUNT_ID, siteId: site.id, filename: d.filename, filePath: key,
      fileType: 'application/pdf', uploadedBy: uploader.id, docType: 'test_report',
      uploadedAt: new Date(d.uploadedAt),
    } });
    console.log('OK: ' + d.site + ' -> "' + d.filename + '" (' + buf.length + ' bytes)');
  }
  console.log('OK: demo documents seeded (' + DOCS.length + ' PDFs).');
}

main().then(() => prisma.$disconnect()).catch(async (e) => { console.error('SEED DOCS ERROR', e); await prisma.$disconnect(); process.exit(1); });
